// 获取输入数据
const inputData = $input.all();

// 存储转换后的数据
const outputData = [];

// 遍历输入数据
inputData.forEach(item => {
  // 检查是否有articles数组
  if (item.json && item.json.articles && Array.isArray(item.json.articles)) {
    // 遍历每篇文章
    item.json.articles.forEach(article => {
      // 格式化发布日期
      let formattedDate = '';
      if (article.publishedAt) {
        const date = new Date(article.publishedAt);
        formattedDate = date.toLocaleString('zh-CN', {
          year: 'numeric',
          month: '2-digit',
          day: '2-digit',
          hour: '2-digit',
          minute: '2-digit'
        });
      }

      // 创建表格行数据
      const tableRow = {
        新闻链接: article.url || '',
        标题: article.title || '',
        新闻简要: article.description || '',
        发布日期: formattedDate,
        作者: article.author || '未知作者'
      };

      outputData.push({
        json: tableRow
      });
    });
  }
});

return outputData;

// 获取 HTTP 请求的输出数据
const articles = $json["articles"];

// 初始化表格数据数组
let tableData = [];

// 遍历所有文章并将其转换成表格格式
articles.forEach(article => {
  const row = {
    "新闻链接": article.url,
    "标题": article.title,
    "新闻简要": article.description,
    "发布日期": article.publishedAt,
    "作者": article.source.name
  };

  tableData.push(row);
});

// 输出结果
return tableData;

