// 处理每个字段，清理控制字符+转义特殊符号
return $input.all().map(item => {
  const cleanField = (value) => {
    if (typeof value !== 'string') return value;
    // 清理控制字符 + 转义双引号
    return value.replace(/[\x00-\x1F\x7F]/g, '').replace(/"/g, '\\"');
  };

  return {
    json: {
      fields: {
        "新闻链接": cleanField(item.json.output['新闻链接']),
        "标题": cleanField(item.json.output['标题']),
        "新闻简要": cleanField(item.json.output['新闻简要']),
        "发布日期": cleanField(item.json.output['发布日期']),
        "作者": cleanField(item.json.output['作者'])
      }
    }
  };
});
